def _token_start_positions(self, tokens: Sequence[int]) -> list[int]:
    """Returns the starting character position of each token, assuming the tokens were
    produced by encoding some text. See `decode_with_offsets` for the offset semantics."""
    token_bytes = self.decode_tokens_bytes(tokens)
    text_len = 0
    positions = []
    for token in token_bytes:
        positions.append(max(0, text_len - (0x80 <= token[0] < 0xC0)))
        text_len += sum(1 for c in token if not 0x80 <= c < 0xC0)
    return positions

def _compress_adjacent_duplicates(self, tokens: list[int]) -> list[int]:
    """Removes adjacent repeated tokens from a token sequence, keeping the first occurrence
    of each run."""
    if not tokens:
        return tokens
    compressed = [tokens[0]]
    for token in tokens[1:]:
        if token != compressed[-1]:
            compressed.append(token)
    return compressed

